bool Assets::InitializePartition()
{
    // Find the partition by name
    const esp_partition_t* partition = esp_partition_find_first(
        ESP_PARTITION_TYPE_DATA, 
        ESP_PARTITION_SUBTYPE_DATA_UNDEFINED, 
        "assets"
    );

    if (partition == nullptr) {
        ESP_LOGE(TAG, "Asset partition not found");
        return false;
    }

    // Check if partition is large enough for our needs
    if (partition->size == 0) {
        ESP_LOGE(TAG, "Asset partition has invalid size");
        return false;
    }

    // Perform checksum validation on the partition data
    uint32_t stored_checksum = 0;
    esp_err_t err = esp_partition_read(partition, 0, &stored_checksum, sizeof(stored_checksum));
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to read checksum from partition: %s", esp_err_to_name(err));
        return false;
    }

    // Map the partition into memory
    esp_partition_mmap_handle_t handle;
    const void* mapped_address;

    err = esp_partition_mmap(partition, 0, partition->size, SPI_FLASH_MMAP_DATA, &mapped_address, &handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to map asset partition: %s", esp_err_to_name(err));
        return false;
    }

    // Store the mapping handle and address for later use
    mmap_handle_ = handle;
    mmap_root_ = (const uint8_t*)mapped_address;
    partition_ = partition;

    // Validate checksum
    if (partition->size > sizeof(uint32_t)) {
        uint32_t calculated_checksum = CalculateChecksum(
            (const char*)mapped_address + sizeof(uint32_t), 
            partition->size - sizeof(uint32_t)
        );

        if (stored_checksum != calculated_checksum) {
            ESP_LOGE(TAG, "Checksum mismatch: expected 0x%x, got 0x%x", stored_checksum, calculated_checksum);
            checksum_valid_ = false;
            esp_partition_munmap(handle);
            return false;
        }
    }

    checksum_valid_ = true;

    // Build asset index from mapped data
    assets_.clear();
    size_t offset = sizeof(uint32_t); // Skip checksum

    while (offset + sizeof(mmap_assets_table) <= partition->size) {
        const mmap_assets_table* asset_entry = (const mmap_assets_table*)(mmap_root_ + offset);

        // Check if we've reached the end of valid entries
        if (asset_entry->asset_name[0] == '\0' || asset_entry->asset_size == 0) {
            break;
        }

        // Validate that this entry fits within the partition
        size_t total_entry_size = sizeof(mmap_assets_table) + asset_entry->asset_size;
        if (offset + total_entry_size > partition->size) {
            ESP_LOGW(TAG, "Asset entry exceeds partition bounds, stopping parsing");
            break;
        }

        // Add asset to our index
        AssetInfo info;
        info.offset = offset + sizeof(mmap_assets_table);
        info.size = asset_entry->asset_size;
        info.width = asset_entry->asset_width;
        info.height = asset_entry->asset_height;

        std::string asset_name(asset_entry->asset_name);
        assets_[asset_name] = info;

        // Move to next entry
        size_t entry_size = sizeof(mmap_assets_table) + asset_entry->asset_size;
        offset += entry_size;

        // Ensure alignment to 4-byte boundary
        offset = (offset + 3) & ~3;
    }

    ESP_LOGI(TAG, "Asset partition initialized successfully, size: %d bytes, assets count: %d", 
             partition->size, assets_.size());
    return true;
}

