bool Assets::Apply()
{
    // Early exit if assets partition is not valid
    if (!partition_valid()) {
        ESP_LOGW(TAG, "Assets partition is disabled for board %s", BOARD_NAME);
        return false;
    }

    // Notify system of upgrade start
    Application::GetInstance().SetDeviceState(kDeviceStateUpgrading);

    auto& assets_instance = Assets::GetInstance();
    bool success = true;

    for (const auto& entry : assets_) {
        const std::string& name = entry.first;

        void* ptr = nullptr;
        size_t size = 0;

        // Attempt to retrieve and validate asset data
        if (!assets_instance.GetAssetData(name, ptr, size)) {
            ESP_LOGE(TAG, "Failed to get valid data for asset '%s'", name.c_str());
            success = false;
            continue;
        }

        // Apply asset - this could involve different actions based on asset type
        ESP_LOGI(TAG, "Applying asset '%s' of size %u", name.c_str(), static_cast<unsigned>(size));

        // Handle different asset types based on name or extension
        if (name.find("font") != std::string::npos) {
            // Handle font assets - assuming CBIN format
            cbin_font_load((const uint8_t*)ptr, size);
        } else if (name.find("image") != std::string::npos) {
            // Handle image assets - store in display system or cache
#ifdef HAVE_LVGL
            // Image assets might be loaded on-demand by LVGL or pre-cached
            // For now, we'll just validate the data structure
            if (size < 4) {
                ESP_LOGE(TAG, "Image asset '%s' is too small", name.c_str());
                success = false;
                continue;
            }
#endif
        } else if (name.find("theme") != std::string::npos) {
            // Handle theme assets
            lvgl_theme_apply((const uint8_t*)ptr, size);
        } else if (name.find("emote") != std::string::npos) {
            // Handle emote assets
            emote_display_load_asset(name, (const uint8_t*)ptr, size);
        } else {
            // Handle other generic assets - could be configuration, data files, etc.
            ESP_LOGD(TAG, "Applied generic asset '%s'", name.c_str());
        }

        // Check for any errors during asset application
        esp_err_t err = esp_rom_get_reset_reason(0); // Dummy check - replace with actual error checking
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Error applying asset '%s': %s", name.c_str(), esp_err_to_name(err));
            success = false;
        }

        // Simulate some processing delay or I/O
        vTaskDelay(pdMS_TO_TICKS(10)); 
    }

    if (!success) {
        ESP_LOGE(TAG, "Some assets failed to apply");
        Application::GetInstance().SetDeviceState(kDeviceStateError);
        return false;
    }

    // Transition to activation phase once all assets are applied
    Application::GetInstance().SetDeviceState(kDeviceStateActivating);

    ESP_LOGI(TAG, "Asset application completed successfully.");
    return true;
}

