#### 1. **HTTP Download with Progress Callback**
This pattern is used in both asset downloading and firmware upgrading, involving opening an HTTP connection, reading data in chunks, and invoking a progress callback periodically.

```cpp
auto network = Board::GetInstance().GetNetwork();
auto http = network->CreateHttp(0);
if (!http->Open("GET", url)) {
    ESP_LOGE(TAG, "Failed to open HTTP connection");
    return false;
}

if (http->GetStatusCode() != 200) {
    ESP_LOGE(TAG, "Failed to get data, status code: %d", http->GetStatusCode());
    return false;
}

size_t content_length = http->GetBodyLength();
if (content_length == 0) {
    ESP_LOGE(TAG, "Failed to get content length");
    return false;
}

char buffer[512];
size_t total_read = 0, recent_read = 0;
auto last_calc_time = esp_timer_get_time();

while (true) {
    int ret = http->Read(buffer, sizeof(buffer));
    if (ret < 0) {
        ESP_LOGE(TAG, "Failed to read HTTP data: %s", esp_err_to_name(ret));
        return false;
    }

    if (ret == 0) {
        break;
    }

    // Process data here (e.g., write to flash)

    recent_read += ret;
    total_read += ret;

    if (esp_timer_get_time() - last_calc_time >= 1000000 || total_read == content_length || ret == 0) {
        size_t progress = total_read * 100 / content_length;
        if (progress_callback) {
            progress_callback(progress, recent_read);
        }
        last_calc_time = esp_timer_get_time();
        recent_read = 0;
    }
}
http->Close();
```

---

#### 2. **Flash Memory Erase Before Write (Sector-based)**  
Used in asset management where sectors are erased just before writing new data. This ensures efficient use of flash without over-erasing.

```cpp
const size_t SECTOR_SIZE = esp_partition_get_main_flash_sector_size();
size_t sectors_to_erase = (content_length + SECTOR_SIZE - 1) / SECTOR_SIZE;
size_t total_erase_size = sectors_to_erase * SECTOR_SIZE;

size_t current_sector = 0;
while (true) {
    // ... read data ...

    size_t write_end_offset = total_written + ret;
    size_t needed_sectors = (write_end_offset + SECTOR_SIZE - 1) / SECTOR_SIZE;

    while (current_sector < needed_sectors) {
        size_t sector_start = current_sector * SECTOR_SIZE;
        esp_err_t err = esp_partition_erase_range(partition_, sector_start, SECTOR_SIZE);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to erase sector %u", current_sector);
            return false;
        }
        current_sector++;
    }

    esp_err_t err = esp_partition_write(partition_, total_written, buffer, ret);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to write to partition");
        return false;
    }

    total_written += ret;
}
```

---

