bool Assets::Download(std::string url, std::function<void(int progress, size_t speed)> progress_callback) {
    // Get network interface from board
    auto* network = Board::GetInstance().GetNetwork();
    if (!network) {
        ESP_LOGE(TAG, "Network interface not available for download");
        return false;
    }

    // Open HTTP connection
    auto http_client = network->OpenHttp(url.c_str());
    if (!http_client) {
        ESP_LOGE(TAG, "Failed to create HTTP client for URL: %s", url.c_str());
        return false;
    }

    // Perform HTTP GET request
    int status_code = http_client->Get();
    if (status_code != 200) {
        ESP_LOGE(TAG, "HTTP GET failed with status code: %d", status_code);
        network->CloseHttp(http_client);
        return false;
    }

    // Get content length
    size_t content_length = http_client->GetContentLength();
    if (content_length == 0) {
        ESP_LOGE(TAG, "Invalid content length received");
        network->CloseHttp(http_client);
        return false;
    }

    ESP_LOGI(TAG, "Starting download of %d bytes from %s", content_length, url.c_str());

    // Validate partition is available
    if (!partition_) {
        ESP_LOGE(TAG, "Assets partition not initialized");
        network->CloseHttp(http_client);
        return false;
    }

    // Erase the partition before writing
    esp_err_t err = esp_partition_erase_range(partition_, 0, partition_->size);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to erase assets partition: %s", esp_err_to_name(err));
        network->CloseHttp(http_client);
        return false;
    }

    // Download and write data in chunks
    const size_t chunk_size = 4096;
    size_t total_downloaded = 0;
    size_t last_progress = 0;
    auto start_time = esp_timer_get_time();

    while (total_downloaded < content_length) {
        char buffer[chunk_size];
        size_t to_read = std::min(chunk_size, content_length - total_downloaded);

        int bytes_read = http_client->Read(buffer, to_read);
        if (bytes_read <= 0) {
            break;
        }

        // Write to flash partition
        err = esp_partition_write(partition_, total_downloaded, buffer, bytes_read);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write to assets partition: %s", esp_err_to_name(err));
            network->CloseHttp(http_client);
            return false;
        }

        total_downloaded += bytes_read;

        // Report progress
        if (progress_callback) {
            size_t current_progress = (total_downloaded * 100) / content_length;
            if (current_progress != last_progress) {
                auto current_time = esp_timer_get_time();
                size_t elapsed_ms = (current_time - start_time) / 1000;
                size_t speed = elapsed_ms > 0 ? (total_downloaded * 1000) / elapsed_ms : 0;

                progress_callback(static_cast<int>(current_progress), speed);
                last_progress = current_progress;
            }
        }
    }

    network->CloseHttp(http_client);

    if (total_downloaded != content_length) {
        ESP_LOGE(TAG, "Download incomplete: %d/%d bytes downloaded", total_downloaded, content_length);
        return false;
    }

    ESP_LOGI(TAG, "Download completed successfully: %d bytes", total_downloaded);

    // Reinitialize partition to validate new content
    if (!InitializePartition()) {
        ESP_LOGE(TAG, "Failed to initialize partition after download");
        return false;
    }

    // Final progress callback
    if (progress_callback) {
        auto end_time = esp_timer_get_time();
        size_t total_time_ms = (end_time - start_time) / 1000;
        size_t average_speed = total_time_ms > 0 ? (total_downloaded * 1000) / total_time_ms : 0;
        progress_callback(100, average_speed);
    }

    return true;
}

