bool Assets::GetAssetData(const std::string& name, void*& ptr, size_t& size) {
    // Check if partition is valid and initialized
    if (!partition_valid_ || !checksum_valid_ || mmap_root_ == nullptr) {
        ESP_LOGE(TAG, "Assets partition is not properly initialized");
        return false;
    }

    // Find the asset in the map
    auto asset = assets_.find(name);
    if (asset == assets_.end()) {
        ESP_LOGD(TAG, "Asset '%s' not found", name.c_str());
        return false;
    }

    // Calculate the actual data pointer
    const char* data = static_cast<const char*>(mmap_root_) + asset->second.offset;

    // Set pointer and size
    ptr = static_cast<void*>(const_cast<char*>(data));
    size = asset->second.size;

    return true;
}

