    size_t content_length = http->GetBodyLength();
    if (content_length == 0) {
        ESP_LOGE(TAG, "Failed to get content length");
        http->Close();
        return false;
    }

    // Begin OTA update
    esp_err_t err = esp_ota_begin(update_partition, OTA_WITH_SEQUENTIAL_WRITES, &update_handle);
    if (err != ESP_OK) {
        ESP_LOGE(TAG, "Failed to begin OTA: %s", esp_err_to_name(err));
        http->Close();
        return false;
    }

    char buffer[512];
    size_t total_read = 0;
    size_t recent_read = 0;
    int64_t last_calc_time = esp_timer_get_time();
    bool success = true;

    // Download and write firmware
    while (true) {
        int ret = http->Read(buffer, sizeof(buffer));
        if (ret < 0) {
            ESP_LOGE(TAG, "Failed to read HTTP data: %d", ret);
            success = false;
            break;
        }

        if (ret == 0) {
            // End of stream
            break;
        }

        // Write data to OTA partition
        err = esp_ota_write(update_handle, buffer, ret);
        if (err != ESP_OK) {
            ESP_LOGE(TAG, "Failed to write OTA data: %s", esp_err_to_name(err));
            success = false;
            break;
        }

        total_read += ret;
        recent_read += ret;

        // Calculate speed and progress every second or at the end
        int64_t current_time = esp_timer_get_time();
        if ((current_time - last_calc_time) >= 1000000 || total_read >= content_length) {
            int progress = (content_length > 0) ? (int)((total_read * 100) / content_length) : 0;
