    std::string payload = GetActivationPayload();

    // Step 3: Construct activation URL
    std::string activation_url = GetCheckVersionUrl();
    // Replace version check endpoint with activation endpoint
    size_t pos = activation_url.find("/version");
    if (pos != std::string::npos) {
        activation_url.replace(pos, 8, "/activate");
    } else {
        // Fallback - append /activate if /version not found
        if (activation_url.back() != '/') {
            activation_url += "/";
        }
        activation_url += "activate";
    }

    // Step 4: Send POST request
    if (!http->Open("POST", activation_url)) {
        ESP_LOGE(TAG, "Failed to open HTTP connection for activation");
        return ESP_ERR_HTTP_CONNECT;
    }

    http->SetContent(std::move(payload));

    auto status_code = http->GetStatusCode();

    if (status_code != 200) {
        ESP_LOGW(TAG, "Activation failed with HTTP status: %d", status_code);
        http->Close();
        return ESP_FAIL;
    }

    std::string response_body = http->ReadAll();
    http->Close();

    // Step 5: Process successful response
    ESP_LOGI(TAG, "Activation successful.");
    ESP_LOG_BUFFER_HEXDUMP(TAG, response_body.data(), response_body.size(), ESP_LOG_DEBUG);

    // Optional: parse and store activation token/license from response here
    cJSON *root = cJSON_Parse(response_body.c_str());
    if (root) {
        cJSON *activated = cJSON_GetObjectItem(root, "activated");
        if (cJSON_IsBool(activated) && cJSON_IsTrue(activated)) {
            ESP_LOGI(TAG, "Device successfully activated");
            cJSON_Delete(root);
            return ESP_OK;
        }
        cJSON_Delete(root);
    }

    return ESP_OK;
}

