void SystemInfo::PrintTaskList()
{
    TaskStatus_t *pxTaskStatusArray;
    UBaseType_t uxArraySize;
    configRUN_TIME_COUNTER_TYPE ulTotalRunTime;

    // Add some extra space to the array size for safety
    #define ARRAY_SIZE_OFFSET 5
    uxArraySize = uxTaskGetNumberOfTasks() + ARRAY_SIZE_OFFSET;

    // Allocate memory for the task status array
    pxTaskStatusArray = (TaskStatus_t*)malloc(sizeof(TaskStatus_t) * uxArraySize);

    if (pxTaskStatusArray != NULL) {
        // Populate the array with task states
        uxArraySize = uxTaskGetSystemState(pxTaskStatusArray, uxArraySize, &ulTotalRunTime);

        if (uxArraySize > 0) {
            // Print header
            ESP_LOGI(TAG, "Task List:");
            ESP_LOGI(TAG, "---------------------------------------------");

            // Iterate over each task and print its information
            for (UBaseType_t x = 0; x < uxArraySize; x++) {
                const char* stateStr;

                switch (pxTaskStatusArray[x].eCurrentState) {
                    case eRunning:   stateStr = "Running"; break;
                    case eReady:     stateStr = "Ready"; break;
                    case eBlocked:   stateStr = "Blocked"; break;
                    case eSuspended: stateStr = "Suspended"; break;
                    case eDeleted:   stateStr = "Deleted"; break;
                    default:         stateStr = "Unknown"; break;
                }

                ESP_LOGI(TAG, "Name: %-16s | State: %-9s | Stack HWM: %u",
                         pxTaskStatusArray[x].pcTaskName,
                         stateStr,
                         (unsigned int)pxTaskStatusArray[x].usStackHighWaterMark);
            }
        } else {
            ESP_LOGW(TAG, "Failed to retrieve task states.");
        }

        // Free the allocated memory
        free(pxTaskStatusArray);
    } else {
        ESP_LOGE(TAG, "Failed to allocate memory for task list.");
    }
}

