void AfeWakeWord::AudioDetectionTask() {
    const EventBits_t DETECTION_BIT = 0x01;
    const size_t FRAME_SIZE = 512; // Assumed frame size per AFE output
    int16_t* audio_frame = new int16_t[FRAME_SIZE];

