void CustomWakeWord::ParseWakenetModelConfig()
{
    char* json_data = nullptr;
    size_t json_size = 0;

    if (!GetAssetData("index.json", json_data, json_size)) {
        ESP_LOGE(TAG, "Failed to load index.json");
        return;
    }

    cJSON* root = cJSON_ParseWithLength(json_data, json_size);
    if (root == nullptr) {
        ESP_LOGE(TAG, "Failed to parse index.json");
        free(json_data);
        return;
    }

    cJSON* language_item = cJSON_GetObjectItem(root, "language");
    if (language_item != nullptr && cJSON_IsString(language_item)) {
        language_ = std::string(cJSON_GetStringValue(language_item));
        ESP_LOGI(TAG, "Language: %s", language_.c_str());
    }

    cJSON* duration_item = cJSON_GetObjectItem(root, "duration");
    if (duration_item != nullptr && cJSON_IsNumber(duration_item)) {
        duration_ = duration_item->valueint;
        ESP_LOGI(TAG, "Duration: %d", duration_);
    }

    cJSON* threshold_item = cJSON_GetObjectItem(root, "threshold");
    if (threshold_item != nullptr && cJSON_IsNumber(threshold_item)) {
        threshold_ = static_cast<float>(threshold_item->valuedouble);
        ESP_LOGI(TAG, "Threshold: %f", threshold_);
    }

    cJSON* commands_array = cJSON_GetObjectItem(root, "commands");
    if (commands_array != nullptr && cJSON_IsArray(commands_array)) {
        commands_.clear();
        int commands_count = cJSON_GetArraySize(commands_array);

        for (int i = 0; i < commands_count; i++) {
            cJSON* command_item = cJSON_GetArrayItem(commands_array, i);
            if (command_item != nullptr && cJSON_IsObject(command_item)) {
                cJSON* command_field = cJSON_GetObjectItem(command_item, "command");
                cJSON* text_field = cJSON_GetObjectItem(command_item, "text");
                cJSON* action_field = cJSON_GetObjectItem(command_item, "action");

                WakeWordCommand cmd;
                if (command_field != nullptr && cJSON_IsString(command_field)) {
                    cmd.command = std::string(cJSON_GetStringValue(command_field));
                }
                if (text_field != nullptr && cJSON_IsString(text_field)) {
                    cmd.text = std::string(cJSON_GetStringValue(text_field));
                }
                if (action_field != nullptr && cJSON_IsString(action_field)) {
                    cmd.action = std::string(cJSON_GetStringValue(action_field));
                }

                commands_.push_back(cmd);
                ESP_LOGI(TAG, "Command: %s, Text: %s, Action: %s", 
