void CustomWakeWord::EncodeWakeWordData()
{
    std::lock_guard<std::mutex> lock(wake_word_mutex_);

    // Clear previous encoded data
    wake_word_opus_.clear();

    if (wake_word_pcm_.empty()) {
        wake_word_cv_.notify_all();
        return;
    }

    // Use existing Opus encoder from AudioService if available
    if (codec_ == nullptr || codec_->opus_encoder_ == nullptr) {
        ESP_LOGE(TAG, "Opus encoder not available");
        wake_word_cv_.notify_all();
        return;
    }

    OpusEncoderWrapper* encoder = codec_->opus_encoder_.get();

    // Reset encoder state
    encoder->Reset();

    const size_t SAMPLE_RATE = 16000;
    const size_t FRAME_SIZE_SAMPLES = 160; // 10ms @ 16kHz
    const size_t FRAME_SIZE_BYTES = FRAME_SIZE_SAMPLES * sizeof(int16_t);

    std::vector<uint8_t> encodedPacket(4096);
    std::vector<uint8_t> fullEncodedData;

    // Process all PCM segments sequentially
    for (const auto& pcmSegment : wake_word_pcm_) {
        if (pcmSegment.empty()) continue;

        size_t totalSamples = pcmSegment.size();
        size_t processedSamples = 0;

        while (processedSamples + FRAME_SIZE_SAMPLES <= totalSamples) {
            int numBytes = opus_encode(
                encoder->encoder_,
                reinterpret_cast<const opus_int16*>(pcmSegment.data() + processedSamples),
                FRAME_SIZE_SAMPLES,
                encodedPacket.data(),
                encodedPacket.size()
            );

            if (numBytes > 0) {
                fullEncodedData.insert(fullEncodedData.end(), encodedPacket.begin(), encodedPacket.begin() + numBytes);
            } else if (numBytes < 0) {
                ESP_LOGE(TAG, "Opus encoding failed: %s", opus_strerror(numBytes));
                break;
            }

            processedSamples += FRAME_SIZE_SAMPLES;
        }
    }

    // Store the encoded data
    if (!fullEncodedData.empty()) {
        wake_word_opus_.push_back(std::move(fullEncodedData));
    }

    // Notify waiting threads that Opus data is available
    wake_word_cv_.notify_all();
}

