            std::vector<float> downsampled_data;
            if (kDownsampleStep > 1.0f) {
                size_t output_size = static_cast<size_t>(audio_data.size() / kDownsampleStep);
                if (output_size > 0) {
                    downsampled_data.reserve(output_size);
                    for (size_t i = 0; i < output_size; ++i) {
                        size_t src_index = static_cast<size_t>(i * kDownsampleStep);
                        if (src_index < audio_data.size()) {
                            downsampled_data.push_back(static_cast<float>(audio_data[src_index]) / 32768.0f);
                        }
                    }
                }
            } else {
                downsampled_data.reserve(audio_data.size());
                for (const int16_t& sample : audio_data) {
                    downsampled_data.push_back(static_cast<float>(sample) / 32768.0f);
                }
            }

            // Process probabilities and decode text
            auto probabilities = signal_processor.ProcessAudioSamples(downsampled_data);

            if (data_buffer.ProcessProbabilityData(probabilities, 0.5f)) {
                if (data_buffer.decoded_text.has_value()) {
                    ESP_LOGI(kLogTag, "Received text data: %s", data_buffer.decoded_text->c_str());
                    display->SetChatMessage("system", data_buffer.decoded_text->c_str());

                    std::string wifi_ssid, wifi_password;
                    size_t newline_position = data_buffer.decoded_text->find('\n');
                    if (newline_position != std::string::npos) {
                        wifi_ssid = data_buffer.decoded_text->substr(0, newline_position);
                        wifi_password = data_buffer.decoded_text->substr(newline_position + 1);
                        ESP_LOGI(kLogTag, "WiFi SSID: %s, Password: %s", wifi_ssid.c_str(), wifi_password.c_str());

                        // Save WiFi credentials
                        auto& ssid_manager = SsidManager::GetInstance();
                        ssid_manager.AddSsid(wifi_ssid, wifi_password);
                        ESP_LOGI(kLogTag, "WiFi credentials saved successfully");

                        // Stop configuration mode
                        wifi_manager->StopConfigAp();

                        data_buffer.decoded_text.reset();
                        return;
                    } else {
                        ESP_LOGE(kLogTag, "Invalid data format, no newline character found");
                        data_buffer.decoded_text.reset();
                        continue;
                    }
                }
            }

            vTaskDelay(pdMS_TO_TICKS(1));
        }

        ESP_LOGI(kLogTag, "Exiting WiFi credential reception mode");
    }
