        uint8_t bit = (probability > threshold) ? 1 : 0;

        // Maintain identifier buffer size
        if (identifier_buffer_.size() >= identifier_buffer_size_) {
            identifier_buffer_.pop_front();
        }
        identifier_buffer_.push_back(bit);

        // State machine handling
        switch (current_state_) {
            case DataReceptionState::kInactive:
                if (identifier_buffer_.size() >= identifier_buffer_size_) {
                    // Check if we have the start pattern in our identifier buffer
                    std::vector<uint8_t> identifier_snapshot(identifier_buffer_.begin(), identifier_buffer_.end());
                    if (identifier_snapshot == start_of_transmission_) {
                        ClearBuffers();
                        current_state_ = DataReceptionState::kReceiving;
                        ESP_LOGI(kLogTag, "Entering Receiving state");
                    }
                }
                break;

            case DataReceptionState::kReceiving:
                bit_buffer_.push_back(bit);

                // Check if we have enough bits to potentially match the end pattern
                if (bit_buffer_.size() >= end_of_transmission_.size()) {
                    // Check if the last bits match the end of transmission pattern
                    bool end_pattern_matched = true;
                    auto bit_it = bit_buffer_.end();
                    auto end_it = end_of_transmission_.rbegin();

                    for (size_t i = 0; i < end_of_transmission_.size(); ++i) {
                        --bit_it;
                        if (*bit_it != *end_it) {
                            end_pattern_matched = false;
                            break;
                        }
                        ++end_it;
                    }

                    if (end_pattern_matched) {
                        // Convert bits to bytes (excluding the end pattern)
                        std::vector<uint8_t> bits_without_end_pattern(
                            bit_buffer_.begin(), 
                            bit_buffer_.end() - end_of_transmission_.size()
                        );
                        std::vector<uint8_t> bytes = ConvertBitsToBytes(bits_without_end_pattern);

                        // Handle checksum validation if enabled
                        uint8_t received_checksum = 0;
                        size_t minimum_length = 0;

                        if (enable_checksum_validation_) {
                            minimum_length = 1; // At least one byte for data plus checksum
                            if (bytes.size() >= minimum_length) {
                                received_checksum = bytes.back();
                            }
                        }

                        // Extract the actual data (excluding checksum if present)
                        if (bytes.size() >= minimum_length) {
                            std::string result(
                                bytes.begin(), 
                                bytes.end() - (enable_checksum_validation_ && !bytes.empty() ? 1 : 0)
                            );

                            // Validate checksum if required
                            if (enable_checksum_validation_ && !bytes.empty()) {
                                uint8_t calculated_checksum = CalculateChecksum(result);
                                if (calculated_checksum != received_checksum) {
                                    ESP_LOGW(kLogTag, "Checksum mismatch: expected %d, got %d", 
                                             calculated_checksum, received_checksum);
                                    ClearBuffers();
                                    current_state_ = DataReceptionState::kInactive;
                                    return false;
                                }
                            }

                            // Process the received data
                            decoded_text = result;
                            ClearBuffers();
                            current_state_ = DataReceptionState::kInactive;
                            return true; // Data successfully received
                        }

                        ClearBuffers();
                        current_state_ = DataReceptionState::kInactive;
                    } else if (bit_buffer_.size() >= max_bit_buffer_size_) {
                        ClearBuffers();
                        current_state_ = DataReceptionState::kInactive;
                    }
                }
                break;
        }
    }

    return false; // No complete data received yet
}

