std::string Board::GenerateUuid()
{
    uint8_t bytes[16];

    // Fill all 16 bytes with random data
    for (int i = 0; i < 16; i += 4) {
        uint32_t random_word = esp_random();
        bytes[i]     = (random_word >> 24) & 0xFF;
        bytes[i + 1] = (random_word >> 16) & 0xFF;
        bytes[i + 2] = (random_word >> 8)  & 0xFF;
        bytes[i + 3] = (random_word)       & 0xFF;
    }

    // Set the UUID version to 4 (bits 12-15 of 7th byte = 0100)
    bytes[6] = (bytes[6] & 0x0F) | 0x40;

    // Set the UUID variant to RFC 4122 (bits 6-7 of 9th byte = 10xx)
    bytes[8] = (bytes[8] & 0x3F) | 0x80;

    // Format as UUID string
    char uuid_str[37]; // 36 characters + null terminator
    snprintf(uuid_str, sizeof(uuid_str),
             "%02x%02x%02x%02x-%02x%02x-%02x%02x-%02x%02x-%02x%02x%02x%02x%02x%02x",
             bytes[0], bytes[1], bytes[2], bytes[3],
             bytes[4], bytes[5],
             bytes[6], bytes[7],
             bytes[8], bytes[9],
             bytes[10], bytes[11], bytes[12], bytes[13], bytes[14], bytes[15]);

    return std::string(uuid_str);
}

