std::string Board::GetSystemInfoJson()
{
    cJSON *root = cJSON_CreateObject();
    if (!root) {
        return "{}";
    }

    // Chip Model Name
    esp_chip_info_t chip_info;
    esp_chip_info(&chip_info);
    const char* chip_model = "Unknown";
    switch(chip_info.model) {
        case ESP_CHIP_MODEL_ESP32:   chip_model = "ESP32"; break;
        case ESP_CHIP_MODEL_ESP32S2: chip_model = "ESP32-S2"; break;
        case ESP_CHIP_MODEL_ESP32S3: chip_model = "ESP32-S3"; break;
        case ESP_CHIP_MODEL_ESP32C3: chip_model = "ESP32-C3"; break;
        case ESP_CHIP_MODEL_ESP32H2: chip_model = "ESP32-H2"; break;
        default:                     chip_model = "Custom/Unknown"; break;
    }
    cJSON_AddStringToObject(root, "chip_model", chip_model);

    // MAC Address - WiFi STA interface assumed
    uint8_t mac[6];
    esp_read_mac(mac, ESP_MAC_WIFI_STA);
    char macStr[18];
    snprintf(macStr, sizeof(macStr), "%02X:%02X:%02X:%02X:%02X:%02X",
             mac[0], mac[1], mac[2], mac[3], mac[4], mac[5]);
    cJSON_AddStringToObject(root, "mac_address", macStr);

    // User Agent Placeholder (no real HTTP client UA here)
    cJSON_AddStringToObject(root, "user_agent", "ESP32-Client/1.0");

    // Flash Size
    size_t flashSize = spi_flash_get_chip_size();
    cJSON_AddNumberToObject(root, "flash_size", static_cast<double>(flashSize));

    // Free Heap
    size_t freeHeap = heap_caps_get_free_size(MALLOC_CAP_INTERNAL);
    cJSON_AddNumberToObject(root, "free_heap", static_cast<double>(freeHeap));

    // Minimum Ever Free Heap
    size_t minFreeHeap = heap_caps_get_minimum_free_size(MALLOC_CAP_INTERNAL);
    cJSON_AddNumberToObject(root, "min_free_heap", static_cast<double>(minFreeHeap));

    // Serialize JSON
    char *jsonString = cJSON_PrintUnformatted(root);
    std::string result = jsonString ? jsonString : "{}";

    // Cleanup
    if (jsonString) {
        free(jsonString);
    }
    cJSON_Delete(root);

    return result;
}

