void SingleLed::OnBlinkTimer() {
    std::lock_guard<std::mutex> lock(mutex_);

    // Handle infinite blinking - never stop
    if (blink_counter_ == BLINK_INFINITE) {
        // Alternate between ON and OFF
        static bool led_on = false;
        if (led_on) {
            // Turn LED off
            led_strip_clear(led_strip_);
            led_strip_refresh(led_strip_);
            led_on = false;
        } else {
            // Turn LED on
            led_strip_set_pixel(led_strip_, 0, r_, g_, b_);
            led_strip_refresh(led_strip_);
            led_on = true;
        }
        return;
    }

    // Handle finite blinking
    if (blink_counter_ == 0) {
        esp_timer_stop(blink_timer_);
        return;
    }

    // Decrement counter
    blink_counter_--;

    // Toggle LED state based on remaining count
    // Even count means turn LED on, odd count means turn LED off
    if ((blink_counter_ & 1) == 0) {
        // Even count - turn LED on
        led_strip_set_pixel(led_strip_, 0, r_, g_, b_);
        led_strip_refresh(led_strip_);
    } else {
        // Odd count - turn LED off
        led_strip_clear(led_strip_);
        led_strip_refresh(led_strip_);
    }

    // Stop timer when counter reaches 0
    if (blink_counter_ == 0) {
        esp_timer_stop(blink_timer_);
    }
}

