bool MqttProtocol::StartMqttClient(bool report_error)
{
    // Ensure we're operating on a live object
    if (!*alive_) {
        if (report_error) {
            ESP_LOGE(TAG, "Attempted to start MQTT client on destroyed object");
        }
        return false;
    }

    // Get settings for MQTT configuration
    auto& settings = Settings::GetInstance();
    auto broker_url = settings.GetMqttBrokerUrl();

    if (broker_url.empty()) {
        if (report_error) {
            ESP_LOGE(TAG, "MQTT broker URL is not configured");
        }
        return false;
    }

    // Destroy existing client if needed
    mqtt_.reset();

    // Create new MQTT client instance using wrapper
    mqtt_ = std::make_unique<MqttClient>(broker_url);
    if (mqtt_ == nullptr) {
        if (report_error) {
            ESP_LOGE(TAG, "Failed to create MQTT client instance");
        }
        return false;
    }

    // Set up event handlers
    mqtt_->SetEventHandler([this](MqttEvent event, const std::string& topic, const std::string& payload) {
        switch (event) {
            case MqttEvent::Connected:
                ESP_LOGI(TAG, "MQTT connected");
                xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
                break;
            case MqttEvent::Disconnected:
                ESP_LOGI(TAG, "MQTT disconnected");
                break;
            case MqttEvent::Data:
                HandleMqttMessage(topic, payload);
                break;
        }
    });

    // Start the MQTT client
    if (!mqtt_->Start()) {
        if (report_error) {
            ESP_LOGE(TAG, "Failed to start MQTT client");
        }
        mqtt_.reset();
        return false;
    }

    // Wait for connection or timeout (simulate with event group)
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        MQTT_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,   // Clear bit on exit
        pdFALSE,  // Wait for any bit
        pdMS_TO_TICKS(10000)); // Timeout after 10 seconds

    if ((bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT) == 0) {
        if (report_error) {
            ESP_LOGW(TAG, "Timeout waiting for MQTT connection");
        }
        mqtt_->Stop();
        mqtt_.reset();
        return false;
    }

    ESP_LOGI(TAG, "MQTT client started successfully");
    return true;
}

