void MqttProtocol::CloseAudioChannel() {
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Send a goodbye message via MQTT to notify the server about channel closure
    cJSON* root = cJSON_CreateObject();
    cJSON_AddStringToObject(root, "type", "goodbye");
    cJSON_AddStringToObject(root, "session_id", session_id_.c_str());
    char* json_str = cJSON_PrintUnformatted(root);
    if (json_str != nullptr) {
        SendText(json_str);
        cJSON_free(json_str);
    }
    cJSON_Delete(root);

    // Reset UDP connection used for audio streaming
    udp_.reset();

    // Clear session information
    session_id_.clear();
    udp_server_.clear();
    udp_port_ = 0;
    aes_nonce_.clear();
    local_sequence_ = 0;
    remote_sequence_ = 0;

    // Notify upper layer that the audio channel has been closed
    if (on_audio_channel_closed_ != nullptr) {
        on_audio_channel_closed_();
    }
}

