bool MqttProtocol::OpenAudioChannel()
{
    std::lock_guard<std::mutex> lock(channel_mutex_);

    // Reset any previous errors
    error_occurred_ = false;
    error_message_.clear();

    // Step 1: Send Hello Message over MQTT
    std::string hello_message = GetHelloMessage();
    if (!mqtt_->Publish(publish_topic_, hello_message)) {
        ESP_LOGE(TAG, "Failed to send hello message over MQTT");
        SetError("MQTT_HELLO_SEND_FAILED");
        return false;
    }

    // Step 2: Wait for Server Response using Event Group
    EventBits_t bits = xEventGroupWaitBits(
        event_group_handle_,
        MQTT_PROTOCOL_SERVER_HELLO_EVENT,
        pdTRUE,   // Clear bits on exit
        pdFALSE,  // Wait for any bit
        pdMS_TO_TICKS(10000)); // Timeout after 10 seconds

    if (!(bits & MQTT_PROTOCOL_SERVER_HELLO_EVENT)) {
        ESP_LOGE(TAG, "Timeout waiting for server hello response");
        SetError("SERVER_HELLO_TIMEOUT");
        return false;
    }

    // Step 3: Initialize UDP Connection for Audio Packets
    auto network = Board::GetInstance().GetNetwork();
    udp_ = network->CreateUdp();
    if (!udp_->Connect(udp_server_, udp_port_)) {
        ESP_LOGE(TAG, "Failed to connect UDP to server %s:%d", udp_server_.c_str(), udp_port_);
        SetError("UDP_CONNECT_FAILURE");
        udp_.reset();
        return false;
    }

    // Step 4: Register UDP Packet Handler
    udp_->OnDataReceived([this](const uint8_t* data, size_t len) {
        // Step 5: Decrypt Received Packet
        std::vector<uint8_t> decrypted_payload;
        if (!DecryptOpusPacket(data, len, decrypted_payload)) {
            ESP_LOGW(TAG, "Failed to decrypt incoming UDP packet");
            return;
        }

        // Step 6: Parse Decrypted Payload into AudioStreamPacket
        auto audio_packet = ParseOpusPacket(decrypted_payload);

        // Step 7: Forward to Registered Audio Callback
        if (on_incoming_audio_ && audio_packet) {
            on_incoming_audio_(std::move(audio_packet));
        }
    });

    ESP_LOGI(TAG, "Audio channel successfully opened");

    return true;
}

