        ESP_LOGW(TAG, "Missing or invalid session_id in server hello");
    }

    // Parse audio parameters
    auto audio_params = cJSON_GetObjectItem(root, "audio_params");
    if (cJSON_IsObject(audio_params)) {
        auto sample_rate = cJSON_GetObjectItem(audio_params, "sample_rate");
        if (cJSON_IsNumber(sample_rate)) {
            server_sample_rate_ = sample_rate->valueint;
        } else {
            ESP_LOGW(TAG, "Missing or invalid sample_rate in audio_params");
        }

        auto frame_duration = cJSON_GetObjectItem(audio_params, "frame_duration");
        if (cJSON_IsNumber(frame_duration)) {
            server_frame_duration_ = frame_duration->valueint;
        } else {
            ESP_LOGW(TAG, "Missing or invalid frame_duration in audio_params");
        }
    } else {
        ESP_LOGW(TAG, "Missing or invalid audio_params in server hello");
    }

    // Parse UDP connection details
    auto host = cJSON_GetObjectItem(root, "host");
    auto port = cJSON_GetObjectItem(root, "port");
    if (cJSON_IsString(host) && cJSON_IsNumber(port)) {
        udp_server_ = host->valuestring;
        udp_port_ = port->valueint;
        ESP_LOGI(TAG, "UDP server: %s:%d", udp_server_.c_str(), udp_port_);
    } else {
        ESP_LOGE(TAG, "Missing or invalid host/port in server hello");
        return;
    }

    // Parse AES key for encryption
    auto aes_key = cJSON_GetObjectItem(root, "aes_key");
    if (cJSON_IsString(aes_key)) {
        auto key_hex = aes_key->valuestring;
        auto key_bytes = DecodeHexString(key_hex);
        if (key_bytes.size() == 16) {  // AES-128
            mbedtls_aes_setkey_enc(&aes_ctx_, (const unsigned char*)key_bytes.data(), 128);
            ESP_LOGI(TAG, "AES key configured successfully");
        } else {
            ESP_LOGE(TAG, "Invalid AES key size: %d bytes", key_bytes.size());
            return;
        }
    } else {
        ESP_LOGE(TAG, "Missing or invalid aes_key in server hello");
        return;
    }

    // Parse AES nonce
    auto aes_nonce = cJSON_GetObjectItem(root, "aes_nonce");
    if (cJSON_IsString(aes_nonce)) {
        aes_nonce_ = DecodeHexString(aes_nonce->valuestring);
        if (aes_nonce_.size() != 16) {
            ESP_LOGE(TAG, "Invalid AES nonce size: %d bytes", aes_nonce_.size());
            return;
        }
        ESP_LOGI(TAG, "AES nonce configured successfully");
    } else {
        ESP_LOGE(TAG, "Missing or invalid aes_nonce in server hello");
        return;
    }

    // Reset sequence numbers
    local_sequence_ = 0;
    remote_sequence_ = 0;

    // Signal completion
    xEventGroupSetBits(event_group_handle_, MQTT_PROTOCOL_SERVER_HELLO_EVENT);
}

