bool WebsocketProtocol::SendAudio(std::unique_ptr<AudioStreamPacket> packet) {
    if (websocket_ == nullptr || !websocket_->IsConnected()) {
        return false;
    }

    if (version_ == 2) {
        // BinaryProtocol2 format:
        // uint16_t version (network byte order)
        // uint16_t type (network byte order)  
        // uint16_t reserved (network byte order)
        // uint32_t timestamp (network byte order)
        // uint32_t payload_size (network byte order)
        // uint8_t payload[payload_size]

        uint32_t payload_size = static_cast<uint32_t>(packet->payload.size());
        std::vector<uint8_t> serialized(2 + 2 + 2 + 4 + 4 + payload_size); // 16 bytes header + payload

        size_t offset = 0;

        // Write header fields in network byte order
        *reinterpret_cast<uint16_t*>(&serialized[offset]) = htons(version_); offset += 2;
        *reinterpret_cast<uint16_t*>(&serialized[offset]) = htons(0); offset += 2; // type
        *reinterpret_cast<uint16_t*>(&serialized[offset]) = htons(0); offset += 2; // reserved
        *reinterpret_cast<uint32_t*>(&serialized[offset]) = htonl(packet->timestamp); offset += 4;
        *reinterpret_cast<uint32_t*>(&serialized[offset]) = htonl(payload_size); offset += 4;

        // Copy payload
        if (payload_size > 0) {
            memcpy(&serialized[offset], packet->payload.data(), payload_size);
        }

        if (!websocket_->Send(reinterpret_cast<const char*>(serialized.data()), serialized.size(), true)) {
            ESP_LOGE(TAG, "Failed to send audio packet (v2)");
            SetError(Lang::Strings::SERVER_ERROR);
            return false;
        }
        return true;

    } else if (version_ == 3) {
        // BinaryProtocol3 format:
        // uint16_t type (host byte order - based on receive code)
        // uint16_t reserved (host byte order - based on receive code) 
        // uint16_t payload_size (network byte order)
        // uint8_t payload[payload_size]

        uint16_t payload_size = static_cast<uint16_t>(packet->payload.size());
        std::vector<uint8_t> serialized(2 + 2 + 2 + payload_size); // 6 bytes header + payload

        size_t offset = 0;

        // Write header fields
        *reinterpret_cast<uint16_t*>(&serialized[offset]) = 0; offset += 2; // type (host order)
        *reinterpret_cast<uint16_t*>(&serialized[offset]) = 0; offset += 2; // reserved (host order)
        *reinterpret_cast<uint16_t*>(&serialized[offset]) = htons(payload_size); offset += 2;

        // Copy payload
        if (payload_size > 0) {
            memcpy(&serialized[offset], packet->payload.data(), payload_size);
        }

        if (!websocket_->Send(reinterpret_cast<const char*>(serialized.data()), serialized.size(), true)) {
            ESP_LOGE(TAG, "Failed to send audio packet (v3)");
            SetError(Lang::Strings::SERVER_ERROR);
            return false;
        }
        return true;

    } else {
        // Raw payload mode
        if (!websocket_->Send(reinterpret_cast<const char*>(packet->payload.data()), packet->payload.size(), true)) {
            ESP_LOGE(TAG, "Failed to send raw audio packet");
            SetError(Lang::Strings::SERVER_ERROR);
