void WebsocketProtocol::ParseServerHello(const cJSON* root) {
    // Validate transport type
    cJSON* transport = cJSON_GetObjectItem(root, "transport");
    if (transport == nullptr || !cJSON_IsString(transport) || strcmp(transport->valuestring, "websocket") != 0) {
        ESP_LOGE(TAG, "Unsupported or missing transport: %s", transport ? transport->valuestring : "null");
        return;
    }

    // Extract session ID if present
